/**
 * Single Page Nav Plugin
 * Modified for Laravel Login/Register support
 */

if (typeof Object.create !== "function") {
    Object.create = function (obj) {
        function F() {}
        F.prototype = obj;
        return new F();
    };
}

(function ($, window, document, undefined) {
    "use strict";

    var SinglePageNav = {

        init: function (options, elem) {
            this.options = $.extend({}, $.fn.singlePageNav.defaults, options);

            this.container = elem;
            this.$container = $(elem);

            // Ambil semua link
            this.$links = this.$container.find("a");

            if (this.options.filter !== "") {
                this.$links = this.$links.filter(this.options.filter);
            }

            this.$window = $(window);
            this.$htmlbody = $("html, body");

            this.$links.on(
                "click.singlePageNav",
                $.proxy(this.handleClick, this)
            );

            this.didScroll = false;

            this.checkPosition();
            this.setTimer();
        },

        handleClick: function (event) {

            var href = event.currentTarget.getAttribute("href");

            // Jika bukan anchor (#), biarkan browser membuka halaman
            if (!href || href.charAt(0) !== "#") {
                return true;
            }

            var self = this,
                link = event.currentTarget,
                target = $(link.hash);

            event.preventDefault();

            if (target.length) {

                self.clearTimer();

                if (typeof self.options.beforeStart === "function") {
                    self.options.beforeStart();
                }

                self.setActiveLink(link.hash);

                self.scrollTo(target, function () {

                    if (
                        self.options.updateHash &&
                        history.pushState
                    ) {
                        history.pushState(null, null, link.hash);
                    }

                    self.setTimer();

                    if (typeof self.options.onComplete === "function") {
                        self.options.onComplete();
                    }
                });
            }
        },

        scrollTo: function (target, callback) {
            var self = this;
            var offsetTop = self.getCoords(target).top;
            var completed = false;

            self.$htmlbody.stop().animate(
                {
                    scrollTop: offsetTop
                },
                {
                    duration: self.options.speed,
                    easing: self.options.easing,
                    complete: function () {
                        if (typeof callback === "function" && !completed) {
                            callback();
                        }
                        completed = true;
                    }
                }
            );
        },

        setTimer: function () {
            var self = this;

            self.$window.on(
                "scroll.singlePageNav",
                function () {
                    self.didScroll = true;
                }
            );

            self.timer = setInterval(function () {
                if (self.didScroll) {
                    self.didScroll = false;
                    self.checkPosition();
                }
            }, 250);
        },

        clearTimer: function () {
            clearInterval(this.timer);
            this.$window.off("scroll.singlePageNav");
            this.didScroll = false;
        },

        checkPosition: function () {
            var scrollTop = this.$window.scrollTop();
            var currentSection = this.getCurrentSection(scrollTop);

            this.setActiveLink(currentSection);
        },

        getCoords: function (element) {
            return {
                top: Math.round(element.offset().top) - this.options.offset
            };
        },

        setActiveLink: function (hash) {
            var $activeLink = this.$container.find(
                "a[href$='" + hash + "']"
            );

            if (!$activeLink.hasClass(this.options.currentClass)) {
                this.$links.removeClass(this.options.currentClass);
                $activeLink.addClass(this.options.currentClass);
            }
        },

        getCurrentSection: function (scrollPos) {
            var i,
                hash,
                coords,
                section;

            for (i = 0; i < this.$links.length; i++) {

                hash = this.$links[i].hash;

                if ($(hash).length) {

                    coords = this.getCoords($(hash));

                    if (
                        scrollPos >=
                        coords.top - this.options.threshold
                    ) {
                        section = hash;
                    }
                }
            }

            return section || this.$links[0].hash;
        }
    };

    $.fn.singlePageNav = function (options) {
        return this.each(function () {
            var instance = Object.create(SinglePageNav);
            instance.init(options, this);
        });
    };

    $.fn.singlePageNav.defaults = {
        offset: 0,
        threshold: 120,
        speed: 400,
        currentClass: "current",
        easing: "swing",
        updateHash: false,
        filter: "",
        onComplete: false,
        beforeStart: false
    };

})(jQuery, window, document);